arguments.file_text:
@page "/privacy"
@using Microsoft.AspNetCore.Http
@attribute [ExcludeFromInteractiveRouting]
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    This application uses cookies to improve your experience.
    We collect only the data necessary to provide our services.
</p>

@if (hasConsented)
{
    <div class="alert alert-success mt-3">
        ✅ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning mt-3">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

@code {
    private bool hasConsented;

    protected override void OnInitialized()
    {
        var context = HttpContextAccessor.HttpContext;
        hasConsented = context?.Request.Cookies.ContainsKey("consent") == true;
    }
}

